#!/usr/bin/env python
"""
Backup script that creates compressed archives of user directories.
Supports multiple compression formats: tar.gz, tar.bz2, zip, 7z
Compatible with Python 2.6+ and Python 3.x
"""

from __future__ import print_function

import os
import sys
import tarfile
import zipfile
import shutil
import subprocess
import datetime
import argparse
import tempfile


SUPPORTED_FORMATS = ['tar.gz', 'tar.bz2', 'zip', '7z']


def get_timestamp():
    """Return a formatted timestamp string for the backup filename."""
    return datetime.datetime.now().strftime('%Y%m%d_%H%M%S')


def get_output_filename(source_dir, fmt, output_dir=None):
    """Generate the output filename based on source directory, format, and timestamp."""
    dir_basename = os.path.basename(os.path.normpath(source_dir))
    timestamp = get_timestamp()
    filename = 'backup_{name}_{ts}'.format(name=dir_basename, ts=timestamp)

    ext_map = {
        'tar.gz': '.tar.gz',
        'tar.bz2': '.tar.bz2',
        'zip': '.zip',
        '7z': '.7z',
    }

    filename += ext_map.get(fmt, '.tar.gz')

    if output_dir:
        if not os.path.isdir(output_dir):
            os.makedirs(output_dir)
        return os.path.join(output_dir, filename)

    return filename


def get_directory_size(path):
    """Calculate total size of a directory in bytes."""
    total_size = 0
    for dirpath, dirnames, filenames in os.walk(path):
        for f in filenames:
            fp = os.path.join(dirpath, f)
            try:
                total_size += os.path.getsize(fp)
            except (OSError, IOError):
                pass
    return total_size


def format_size(size_bytes):
    """Format bytes into a human-readable string."""
    for unit in ['B', 'KB', 'MB', 'GB', 'TB']:
        if size_bytes < 1024.0:
            return '{size:.2f} {unit}'.format(size=size_bytes, unit=unit)
        size_bytes /= 1024.0
    return '{size:.2f} PB'.format(size=size_bytes)


def check_7z_available():
    """Check if the 7z command-line tool is available."""
    try:
        devnull = open(os.devnull, 'w')
        subprocess.call(['7z'], stdout=devnull, stderr=devnull)
        devnull.close()
        return True
    except (OSError, IOError):
        pass

    try:
        devnull = open(os.devnull, 'w')
        subprocess.call(['7za'], stdout=devnull, stderr=devnull)
        devnull.close()
        return '7za'
    except (OSError, IOError):
        pass

    return False


def create_tar_gz(source_dir, output_file, verbose=False):
    """Create a tar.gz compressed archive."""
    print('Creating tar.gz archive: {0}'.format(output_file))
    file_count = 0

    try:
        with tarfile.open(output_file, 'w:gz') as tar:
            for root, dirs, files in os.walk(source_dir):
                for f in files:
                    filepath = os.path.join(root, f)
                    arcname = os.path.relpath(filepath, os.path.dirname(source_dir))
                    try:
                        tar.add(filepath, arcname=arcname)
                        file_count += 1
                        if verbose:
                            print('  Added: {0}'.format(arcname))
                    except (OSError, IOError, tarfile.TarError) as e:
                        print('  WARNING: Could not add {0}: {1}'.format(filepath, e), file=sys.stderr)
                # Also add empty directories
                for d in dirs:
                    dirpath = os.path.join(root, d)
                    arcname = os.path.relpath(dirpath, os.path.dirname(source_dir))
                    try:
                        tar.add(dirpath, arcname=arcname, recursive=False)
                    except (OSError, IOError, tarfile.TarError):
                        pass

        print('Successfully archived {0} files.'.format(file_count))
        return True
    except Exception as e:
        print('ERROR: Failed to create tar.gz archive: {0}'.format(e), file=sys.stderr)
        return False


def create_tar_bz2(source_dir, output_file, verbose=False):
    """Create a tar.bz2 compressed archive."""
    print('Creating tar.bz2 archive: {0}'.format(output_file))
    file_count = 0

    try:
        with tarfile.open(output_file, 'w:bz2') as tar:
            for root, dirs, files in os.walk(source_dir):
                for f in files:
                    filepath = os.path.join(root, f)
                    arcname = os.path.relpath(filepath, os.path.dirname(source_dir))
                    try:
                        tar.add(filepath, arcname=arcname)
                        file_count += 1
                        if verbose:
                            print('  Added: {0}'.format(arcname))
                    except (OSError, IOError, tarfile.TarError) as e:
                        print('  WARNING: Could not add {0}: {1}'.format(filepath, e), file=sys.stderr)
                for d in dirs:
                    dirpath = os.path.join(root, d)
                    arcname = os.path.relpath(dirpath, os.path.dirname(source_dir))
                    try:
                        tar.add(dirpath, arcname=arcname, recursive=False)
                    except (OSError, IOError, tarfile.TarError):
                        pass

        print('Successfully archived {0} files.'.format(file_count))
        return True
    except Exception as e:
        print('ERROR: Failed to create tar.bz2 archive: {0}'.format(e), file=sys.stderr)
        return False


def create_zip(source_dir, output_file, verbose=False):
    """Create a zip compressed archive."""
    print('Creating zip archive: {0}'.format(output_file))
    file_count = 0

    try:
        # Use ZIP_DEFLATED if available, fall back to ZIP_STORED
        try:
            import zlib  # noqa: F401
            compression = zipfile.ZIP_DEFLATED
        except ImportError:
            print('  NOTE: zlib not available, using stored (uncompressed) zip.', file=sys.stderr)
            compression = zipfile.ZIP_STORED

        zf = zipfile.ZipFile(output_file, 'w', compression)
        try:
            for root, dirs, files in os.walk(source_dir):
                # Add empty directories
                for d in dirs:
                    dirpath = os.path.join(root, d)
                    arcname = os.path.relpath(dirpath, os.path.dirname(source_dir)) + '/'
                    try:
                        zf.write(dirpath, arcname)
                    except (OSError, IOError):
                        pass

                for f in files:
                    filepath = os.path.join(root, f)
                    arcname = os.path.relpath(filepath, os.path.dirname(source_dir))
                    try:
                        zf.write(filepath, arcname)
                        file_count += 1
                        if verbose:
                            print('  Added: {0}'.format(arcname))
                    except (OSError, IOError) as e:
                        print('  WARNING: Could not add {0}: {1}'.format(filepath, e), file=sys.stderr)
        finally:
            zf.close()

        print('Successfully archived {0} files.'.format(file_count))
        return True
    except Exception as e:
        print('ERROR: Failed to create zip archive: {0}'.format(e), file=sys.stderr)
        return False


def create_7z(source_dir, output_file, verbose=False):
    """Create a 7z compressed archive using the 7z command-line tool."""
    print('Creating 7z archive: {0}'.format(output_file))

    sevenzip_check = check_7z_available()
    if not sevenzip_check:
        print('ERROR: 7z/7za command not found. Please install p7zip or p7zip-full.', file=sys.stderr)
        print('  On Debian/Ubuntu: sudo apt-get install p7zip-full', file=sys.stderr)
        print('  On CentOS/RHEL: sudo yum install p7zip p7zip-plugins', file=sys.stderr)
        return False

    cmd_name = sevenzip_check if isinstance(sevenzip_check, str) else '7z'

    cmd = [cmd_name, 'a']
    if not verbose:
        cmd.append('-bd')  # Disable progress indicator
    cmd.extend([output_file, source_dir])

    try:
        if verbose:
            ret = subprocess.call(cmd)
        else:
            devnull = open(os.devnull, 'w')
            ret = subprocess.call(cmd, stdout=devnull, stderr=devnull)
            devnull.close()

        if ret == 0:
            print('Successfully created 7z archive.')
            return True
        else:
            print('ERROR: 7z command exited with code {0}'.format(ret), file=sys.stderr)
            return False
    except Exception as e:
        print('ERROR: Failed to create 7z archive: {0}'.format(e), file=sys.stderr)
        return False


def validate_source_directory(source_dir):
    """Validate the source directory exists and is readable."""
    if not os.path.exists(source_dir):
        print('ERROR: Directory does not exist: {0}'.format(source_dir), file=sys.stderr)
        return False

    if not os.path.isdir(source_dir):
        print('ERROR: Path is not a directory: {0}'.format(source_dir), file=sys.stderr)
        return False

    if not os.access(source_dir, os.R_OK):
        print('ERROR: Directory is not readable: {0}'.format(source_dir), file=sys.stderr)
        return False

    return True


def validate_output_writable(output_file):
    """Check if we can write to the output location."""
    output_dir = os.path.dirname(os.path.abspath(output_file))
    if not os.path.isdir(output_dir):
        try:
            os.makedirs(output_dir)
        except (OSError, IOError) as e:
            print('ERROR: Cannot create output directory {0}: {1}'.format(output_dir, e), file=sys.stderr)
            return False

    if not os.access(output_dir, os.W_OK):
        print('ERROR: Output directory is not writable: {0}'.format(output_dir), file=sys.stderr)
        return False

    return True


def check_disk_space(source_dir, output_file):
    """Warn if disk space might be insufficient (best effort check)."""
    try:
        source_size = get_directory_size(source_dir)
        print('Source directory size: {0}'.format(format_size(source_size)))

        # Try to check available disk space (Python 3.3+ or using os.statvfs)
        output_dir = os.path.dirname(os.path.abspath(output_file))
        try:
            if hasattr(shutil, 'disk_usage'):
                # Python 3.3+
                usage = shutil.disk_usage(output_dir)
                available = usage.free
            elif hasattr(os, 'statvfs'):
                # Unix systems
                stat = os.statvfs(output_dir)
                available = stat.f_bavail * stat.f_frsize
            else:
                return True  # Can't check, assume OK

            print('Available disk space: {0}'.format(format_size(available)))

            # Warn if available space is less than source size (compressed will be smaller, but be safe)
            if available < source_size:
                print('WARNING: Available disk space ({0}) may be less than source size ({1}).'.format(
                    format_size(available), format_size(source_size)), file=sys.stderr)
                print('The compressed archive will likely be smaller, but proceed with caution.',
                      file=sys.stderr)
                return True  # Still allow proceeding

        except (OSError, IOError):
            pass  # Can't check disk space, that's OK

        return True

    except Exception:
        return True  # Don't block on disk space check failure


def create_backup(source_dir, fmt, output_dir=None, verbose=False, dry_run=False):
    """
    Main backup function that orchestrates the archive creation.

    Args:
        source_dir: Path to the directory to back up
        fmt: Compression format (tar.gz, tar.bz2, zip, 7z)
        output_dir: Optional output directory for the archive
        verbose: Whether to print detailed file listing
        dry_run: If True, only show what would be done

    Returns:
        The output filename on success, None on failure
    """
    source_dir = os.path.abspath(source_dir)

    if not validate_source_directory(source_dir):
        return None

    if fmt not in SUPPORTED_FORMATS:
        print('ERROR: Unsupported format "{0}". Supported formats: {1}'.format(
            fmt, ', '.join(SUPPORTED_FORMATS)), file=sys.stderr)
        return None

    output_file = get_output_filename(source_dir, fmt, output_dir)
    output_file = os.path.abspath(output_file)

    if not validate_output_writable(output_file):
        return None

    print('=' * 60)
    print('Backup Configuration:')
    print('  Source:      {0}'.format(source_dir))
    print('  Format:      {0}'.format(fmt))
    print('  Output:      {0}'.format(output_file))
    print('  Verbose:     {0}'.format(verbose))
    print('=' * 60)

    check_disk_space(source_dir, output_file)

    if dry_run:
        print('\nDRY RUN: No archive will be created.')
        print('Would create: {0}'.format(output_file))
        return output_file

    print('')

    # Dispatch to the appropriate handler
    format_handlers = {
        'tar.gz': create_tar_gz,
        'tar.bz2': create_tar_bz2,
        'zip': create_zip,
        '7z': create_7z,
    }

    handler = format_handlers.get(fmt)
    if handler is None:
        print('ERROR: No handler for format: {0}'.format(fmt), file=sys.stderr)
        return None

    success = handler(source_dir, output_file, verbose=verbose)

    if success and os.path.exists(output_file):
        archive_size = os.path.getsize(output_file)
        source_size = get_directory_size(source_dir)
        print('')
        print('Backup complete!')
        print('  Archive:     {0}'.format(output_file))
        print('  Archive size: {0}'.format(format_size(archive_size)))
        if source_size > 0:
            ratio = (1.0 - float(archive_size) / float(source_size)) * 100
            print('  Compression: {0:.1f}% reduction'.format(ratio))
        return output_file
    elif success:
        # Handler said success but file doesn't exist (shouldn't happen)
        print('WARNING: Handler reported success but archive file not found.', file=sys.stderr)
        return None
    else:
        # Clean up partial file on failure
        if os.path.exists(output_file):
            try:
                os.remove(output_file)
                print('Cleaned up partial archive file.', file=sys.stderr)
            except (OSError, IOError):
                pass
        return None


def parse_arguments(args=None):
    """Parse command-line arguments with fallback for older Python versions."""
    try:
        parser = argparse.ArgumentParser(
            description='Create compressed backups of user directories.',
            epilog='Supported formats: {0}'.format(', '.join(SUPPORTED_FORMATS)),
        )
        parser.add_argument(
            'directory',
            help='Path to the directory to back up',
        )
        parser.add_argument(
            '-f', '--format',
            choices=SUPPORTED_FORMATS,
            default='tar.gz',
            dest='fmt',
            help='Compression format (default: tar.gz)',
        )
        parser.add_argument(
            '-o', '--output-dir',
            default=None,
            help='Output directory for the archive (default: current directory)',
        )
        parser.add_argument(
            '-v', '--verbose',
            action='store_true',
            default=False,
            help='Show detailed file listing during archive creation',
        )
        parser.add_argument(
            '-n', '--dry-run',
            action='store_true',
            default=False,
            help='Show what would be done without creating the archive',
        )
        parser.add_argument(
            '--list-formats',
            action='store_true',
            default=False,
            help='List supported formats and exit',
        )

        parsed = parser.parse_args(args)
        return parsed

    except SystemExit:
        raise
    except Exception:
        # Fallback for very old Python without argparse
        return _parse_arguments_fallback(args)


def _parse_arguments_fallback(args=None):
    """Fallback argument parser for systems without argparse (Python < 2.7)."""
    import getopt

    if args is None:
        args = sys.argv[1:]

    class Args(object):
        def __init__(self):
            self.directory = None
            self.fmt = 'tar.gz'
            self.output_dir = None
            self.verbose = False
            self.dry_run = False
            self.list_formats = False

    parsed = Args()

    try:
        opts, remaining = getopt.getopt(
            args,
            'f:o:vnh',
            ['format=', 'output-dir=', 'verbose', 'dry-run', 'list-formats', 'help']
        )
    except getopt.GetoptError as e:
        print('Error: {0}'.format(e), file=sys.stderr)
        print('Usage: {0} [-f FORMAT] [-o OUTPUT_DIR] [-v] [-n] DIRECTORY'.format(sys.argv[0]),
              file=sys.stderr)
        sys.exit(2)

    for opt, val in opts:
        if opt in ('-h', '--help'):
            print('Usage: {0} [-f FORMAT] [-o OUTPUT_DIR] [-v] [-n] DIRECTORY'.format(sys.argv[0]))
            print('Supported formats: {0}'.format(', '.join(SUPPORTED_FORMATS)))
            sys.exit(0)
        elif opt in ('-f', '--format'):
            parsed.fmt = val
        elif opt in ('-o', '--output-dir'):
            parsed.output_dir = val
        elif opt in ('-v', '--verbose'):
            parsed.verbose = True
        elif opt in ('-n', '--dry-run'):
            parsed.dry_run = True
        elif opt == '--list-formats':
            parsed.list_formats = True

    if remaining:
        parsed.directory = remaining[0]

    return parsed


def main():
    """Main entry point."""
    parsed = parse_arguments()

    if parsed.list_formats:
        print('Supported compression formats:')
        for fmt in SUPPORTED_FORMATS:
            notes = []
            if fmt in ('tar.gz', 'tar.bz2', 'zip'):
                notes.append('built-in')
            if fmt == '7z':
                available = check_7z_available()
                if available:
                    notes.append('available')
                else:
                    notes.append('NOT AVAILABLE - install p7zip')
            print('  {fmt:10s} ({notes})'.format(fmt=fmt, notes=', '.join(notes)))
        sys.exit(0)

    if not parsed.directory:
        print('ERROR: No directory specified.', file=sys.stderr)
        print('Usage: {0} [-f FORMAT] [-o OUTPUT_DIR] [-v] [-n] DIRECTORY'.format(sys.argv[0]),
              file=sys.stderr)
        sys.exit(1)

    result = create_backup(
        source_dir=parsed.directory,
        fmt=parsed.fmt,
        output_dir=parsed.output_dir,
        verbose=parsed.verbose,
        dry_run=parsed.dry_run,
    )

    if result is None:
        sys.exit(1)
    else:
        sys.exit(0)


if __name__ == '__main__':
    main()